    getCompatibleProducts() {

        get('{ site { product (entityId: ' + this.context.productId + ') { name, entityId, categories { edges { node { name, path } } } } } }', false).then((data) => {
            const productData = data.site;
            const categoryList = productData.product.categories.edges;
            let compatibleProductName;
            let compatibleProductUrl;
            const compatibleList = document.getElementById("compatible-list");

            if (compatibleList != null) {
                for (let i = 0; i < categoryList.length; i++) {
                    compatibleProductName = categoryList[i].node.name;
                    compatibleProductUrl = categoryList[i].node.path;

                    // Create li and a tags
                    const listItem = document.createElement("li");
                    const listItemAnchor = document.createElement("a");

                    // Add category url and name
                    const textnode = document.createTextNode(compatibleProductName);
                    listItemAnchor.href = compatibleProductUrl;

                    // Create and add the children elements to the list
                    listItem.appendChild(listItemAnchor);
                    listItemAnchor.appendChild(textnode);
                    compatibleList.appendChild(listItem);
                }
            }

        })
    }
